module RefModule (
    input clk,
    input rst,
    output [11:0] q
);

    reg [11:0] q_reg;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
        if (rst)
            q_reg <= 12'b000000000000;
        else
            q_reg <= q_reg + 2;
    end

    assign q = q_reg;

endmodule
